/// <summary>
/// Subscribes to PersistentComponentState on the server so that the
/// authenticated user's claims are serialized into the prerendered page
/// and picked up by the client-side PersistentAuthenticationStateProvider.
/// </summary>
public sealed class PersistingServerAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly HardcodedAuthenticationStateProvider _inner;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingServerAuthenticationStateProvider(
        PersistentComponentState persistentComponentState,
        HardcodedAuthenticationStateProvider inner)
    {
        _state = persistentComponentState;
        _inner = inner;
        _subscription = _state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        _authenticationStateTask ??= _inner.GetAuthenticationStateAsync();
        return _authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var user = authState.User;

        if (user.Identity?.IsAuthenticated != true)
            return;

        var email = user.FindFirstValue(ClaimTypes.Email) ?? user.Identity.Name ?? "";
        var roles = user.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

        _state.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Email = email,
            Roles = roles,
        });
    }

    public void Dispose() => _subscription.Dispose();
}

